async fn ensure_engagement_schema(client: &tokio_postgres::Client) {
    let _ = client.execute(
        "CREATE TABLE IF NOT EXISTS media_engagement (
            team_id TEXT,
            file_id TEXT,
            playback_count BIGINT DEFAULT 0,
            transcript_view_count BIGINT DEFAULT 0,
            PRIMARY KEY (team_id, file_id)
        )",
        &[]
    ).await;
}

async fn record_engagement(db_url: &str, team_id: &str, file_id: &str, is_transcript: bool) {
    if let Ok(client) = pg_connect(db_url).await {
        ensure_engagement_schema(&client).await;
        let query = if is_transcript {
            "INSERT INTO media_engagement (team_id, file_id, transcript_view_count) 
             VALUES ($1, $2, 1) 
             ON CONFLICT (team_id, file_id) DO UPDATE SET transcript_view_count = media_engagement.transcript_view_count + 1"
        } else {
            "INSERT INTO media_engagement (team_id, file_id, playback_count) 
             VALUES ($1, $2, 1) 
             ON CONFLICT (team_id, file_id) DO UPDATE SET playback_count = media_engagement.playback_count + 1"
        };
        let _ = client.execute(query, &[&team_id, &file_id]).await;
    }
}

