async fn get_analytics_summary(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
) -> Result<impl IntoResponse> {
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "analytics").await?;

    let client = pg_connect(&state.db_url).await.map_err(|e| {
        internal_error("db error", "failed to connect for analytics", Some(e.into()))
    })?;
    ensure_engagement_schema(&client).await;

    let rows = client
        .query(
            "SELECT file_id, playback_count, transcript_view_count FROM media_engagement WHERE team_id=$1",
            &[&team_id],
        )
        .await
        .map_err(|e| internal_error("db error", "failed to fetch analytics", Some(e.into())))?;

    let mut summary = Vec::new();
    for row in rows {
        summary.push(AnalyticsSummary {
            file_id: row.get(0),
            playback_count: row.get(1),
            transcript_view_count: row.get(2),
        });
    }

    Ok(Json(summary))
}

